		reg.exe add "HKU\DefaultUser\Software\Microsoft\Windows\CurrentVersion\RunOnce" /v "UnattendedSetup" /t REG_SZ /d "powershell.exe -WindowStyle Normal -NoProfile -Command \""Get-Content -LiteralPath 'C:\Windows\Setup\Scripts\UserOnce.ps1' -Raw | Invoke-Expression;\""" /f;
	};
);

& {
  [float] $complete = 0;
  [float] $increment = 100 / $scripts.Count;
  foreach( $script in $scripts ) {
    Write-Progress -Activity 'Running scripts to modify the default user’’s registry hive. Do not close this window.' -PercentComplete $complete;
    '*** Will now execute command «{0}».' -f $(
      $str = $script.ToString().Trim() -replace '\s+', ' ';
      $max = 100;
      if( $str.Length -le $max ) {
        $str;
      } else {
        $str.Substring( 0, $max - 1 ) + '…';
      }
    );
    $start = [datetime]::Now;
    & $script;
    '*** Finished executing command after {0:0} ms.' -f [datetime]::Now.Subtract( $start ).TotalMilliseconds;
    "`r`n" * 3;
    $complete += $increment;
  }
} *>&1 >> "C:\Windows\Setup\Scripts\DefaultUser.log";

# Script: Detectar tipo de equipo, asignar nombre alfanum?rico y registrar log
# -------------------------------------------------------------
# Ruta fija del log
$logFile = "C:\Windows\Setup\Scripts\Equipo.log"

# Funci?n para escribir en log
function Write-Log {
    param([string]$msg)
    $msg | Tee-Object -FilePath $logFile -Append
}
# Generar nombre alfanum?rico de 7 caracteres (letras y n?meros)
function Get-RandomName {
    $chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
    -join ((1..7) | ForEach-Object { $chars[(Get-Random -Maximum $chars.Length)] })
}
# Mapear c?digos de chasis a Desktop/Laptop v?lidos
$desktopCodes = @(3,4,5,6,7,15,16,35)
$laptopCodes  = @(8,9,10,14,17,30,31,32)
# C?digos a ignorar
$ignoreCodes = @(11,12,18,19,20,21,22,25,26,27)
# Obtener info del equipo
$cs = Get-CimInstance -ClassName Win32_ComputerSystem
$chassis = Get-CimInstance -ClassName Win32_SystemEnclosure
# Detectar tipo de disco principal
$disk = Get-PhysicalDisk | Sort-Object -Property Size -Descending | Select-Object -First 1
if ($disk.MediaType -eq "SSD") {
    $disco = "SSD"
}
elseif ($disk.MediaType -eq "HDD") {
    $disco = "HDD"
}
else {
    $disco = "Desconocido"
}

$finalName = $null
$tipo = "Desconocido"

foreach ($c in $chassis) {
    foreach ($code in $c.ChassisTypes) {
        if ($ignoreCodes -contains $code) {
            Write-Log "C?digo $code detectado (Ignorado)."
            continue
        }

        if ($desktopCodes -contains $code) {
            $tipo = "Desktop"
        }
        elseif ($laptopCodes -contains $code) {
            $tipo = "Laptop"
        }
        else {
            $tipo = "No identificado"
        }

        # Solo procesa Desktop y Laptop
        if ($tipo -eq "Desktop" -or $tipo -eq "Laptop") {
            $finalName = "$tipo-" + (Get-RandomName)

            # Log detallado
            Write-Log "===================================="
            Write-Log "Fecha: $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')"
            Write-Log "Chassis Code: $code"
            Write-Log "Disco: $disco"
            Write-Log "Tipo Detectado: $tipo"
            Write-Log "Nombre asignado: $finalName"
            Write-Log "===================================="
            break
        }
    }
}

if ($null -ne $finalName) {
    # Renombrar el equipo
    Rename-Computer -NewName $finalName -Force
    Write-Host "El equipo se renombr? a: $finalName"
    Write-Host "Log guardado en: $logFile"
} else {
    Write-Host "No se pudo determinar el tipo de equipo. El nombre no fue cambiado."
}

