# Ruta de descarga y extracción $zipUrl = "https://github.com/mggons93/OptimizeUpdate/raw/refs/heads/main/Programs/VistaCursors.zip" # ← Reemplaza con tu URL real $zipPath = "$env:TEMP\VistaCursors.zip" $extractPath = "C:\Windows\Cursors"
# Descargar el ZIP Invoke-WebRequest -Uri $zipUrl -OutFile $zipPath
