# Aplicar los cursores al registro foreach ($role in $cursorMap.Keys) { if (Test-Path $cursorMap[$role]) { Set-ItemProperty -Path "HKCU:\Control Panel\Cursors" -Name $role -Value $cursorMap[$role] } else { Write-Warning "Cursor no encontrado: $cursorMap[$role]" } }
