# --- Helper: obtener ruta a powershell.exe adecuada ---
function Get-PowerShellPath {
    $isOs64 = [Environment]::Is64BitOperatingSystem
    $isProc64 = [Environment]::Is64BitProcess
    if ($isOs64 -and -not $isProc64) {
        $sysnative = Join-Path $env:WINDIR "Sysnative\WindowsPowerShell\v1.0\powershell.exe"
        if (Test-Path $sysnative) { return $sysnative }
    }
    return Join-Path $env:WINDIR "System32\WindowsPowerShell\v1.0\powershell.exe"
}

# --- Paths y variables principales ---
$exeName = 'FirstlogonGUI.App.exe'
$exePath = 'C:\Windows\Setup\Scripts\FirstlogonGUI.App.exe'
$logFile = 'C:\Windows\Setup\Scripts\Launcher.log'
$taskName = 'FirstLogonGUI_Launcher_Task'
$markerPath = 'C:\Windows\Setup\Scripts\FirstlogonGUI.installed'
$stateFilePath = 'C:\Windows\Setup\Scripts\state.json'
$downloadUrl = 'https://github.com/mggons93/OptimizeUpdate/releases/download/V2.0.1/FirstlogonGUI.App.exe'

