$mutex = New-Object System.Threading.Mutex($false, $mutexName)
if (-not $mutex.WaitOne(0)) { Write-Host "Otra instancia ya está ejecutándose" -ForegroundColor Yellow; exit 0 }

# --- Logging ---
function Write-Log {
    param([string]$msg)
    $entry = "[$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')] $msg"
    try { Add-Content -Path $logFile -Value $entry -Encoding UTF8 } catch {}
}

function Show-Info {
    param([string]$msg, [ConsoleColor]$color = 'White')
    try { Write-Host $msg -ForegroundColor $color } catch {}
    try { Write-Log $msg } catch {}
}

# --- Detect ClearDir entry ---
function Get-ClearDirEntry {
    param([string]$StateFilePath)
    if (-not (Test-Path $StateFilePath)) { return $null }
    try {
        $arr = (Get-Content -Path $StateFilePath -Raw) | ConvertFrom-Json
    } catch {
        Write-Log ("Get-ClearDirEntry: error parseando " + $StateFilePath + ": " + $_.Exception.Message)
        return $null
    }
    foreach ($item in $arr) {
        if ($item.name -eq 'ClearDir') { return $item }
    }
    return $null
}

# --- Remove scheduled task ---
function Remove-LauncherScheduledTask {
    try {
        if (Get-ScheduledTask -TaskName $taskName -ErrorAction SilentlyContinue) {
            Unregister-ScheduledTask -TaskName $taskName -Confirm:$false -ErrorAction SilentlyContinue
            Write-Log "Tarea programada eliminada: $taskName"
        } else {
            Write-Log "No existía tarea programada: $taskName"
        }
    } catch {
        Write-Log "Error eliminando tarea programada: $($_.Exception.Message)"
    }
}

# --- Register scheduled task (sin Delay incompatible) ---
function Register-LauncherScheduledTask {
    $fixedScriptPath = 'C:\Windows\Setup\Scripts\launcher.ps1'

    if (-not (Test-Path $fixedScriptPath)) {
        Write-Log "ERROR: ruta fija no existe: $fixedScriptPath. Abortando registro de tarea."
        return
    }

    $psExe = Get-PowerShellPath
    $actionArgs = "-NoProfile -ExecutionPolicy Bypass -File `"$fixedScriptPath`""
    $currentUser = "$env:USERDOMAIN\$env:USERNAME"

    try {
        if (Get-ScheduledTask -TaskName $taskName -ErrorAction SilentlyContinue) {
            Unregister-ScheduledTask -TaskName $taskName -Confirm:$false -ErrorAction SilentlyContinue
            Start-Sleep -Seconds 1
        }

        $action = New-ScheduledTaskAction -Execute $psExe -Argument $actionArgs
        $trigger = New-ScheduledTaskTrigger -AtLogOn   
        $principal = New-ScheduledTaskPrincipal -UserId $currentUser -LogonType Interactive -RunLevel Highest
        $settings = New-ScheduledTaskSettingsSet -AllowStartIfOnBatteries -DontStopIfGoingOnBatteries -StartWhenAvailable -MultipleInstances IgnoreNew

        $task = New-ScheduledTask -Action $action -Trigger $trigger -Principal $principal -Settings $settings -Description "FirstLogonGUI launcher"

        Register-ScheduledTask -TaskName $taskName -InputObject $task -Force

        Write-Log "Tarea programada registrada: $taskName para usuario $currentUser"
        Write-Log "CmdLine tarea: $psExe $actionArgs"
    } catch {
        Write-Log "Error registrando tarea programada: $($_.Exception.Message)"
    }
}

# --- Ensure scheduled task registered only when needed ---
function Ensure-LauncherScheduledTaskRegistered {
    param([string]$state)

    if (Test-Path $markerPath) {
        Write-Log "Marcador ya existe ($markerPath). No se registra tarea."
        return
    }

    if ($state -ne "pending") {
        Write-Log "No se registra tarea porque state=$state"
        return
    }

    Write-Log "Registrando tarea programada (state=pending)..."
    Register-LauncherScheduledTask
}

# --- Cleanup final ---
function Invoke-LauncherCleanup {
    param([string]$Status)
    Write-Log "Invoke-LauncherCleanup: $Status"

    if ($Status -eq 'done') { Show-Info "ClearDir completado: limpiando tarea programada" Green }
    elseif ($Status -eq 'error') { Show-Info "ClearDir error: limpiando tarea programada" Yellow }

    Remove-LauncherScheduledTask

    if ($Status -eq 'done') {
        try {
            New-Item -Path $markerPath -ItemType File -Force | Out-Null
            Show-Info "Marcador creado: $markerPath" Green
            Write-Log "Marcador creado: $markerPath"
        } catch {
            Write-Log "Error creando marcador: $($_.Exception.Message)"
        }
    }

    exit 0
}

# --- Internet check ---
function Wait-ForInternet {
    Write-Log "Comprobando conexion a Internet real..."
    Show-Info "Comprobando conexion a Internet..." Yellow
    while ($true) {
        try {
            $response = Invoke-WebRequest -Uri "http://clients3.google.com/generate_204" -UseBasicParsing -TimeoutSec 3
            if ($response.StatusCode -eq 204) { Write-Log "Internet OK"; Show-Info "Conexión a Internet detectada." Green; break }
        } catch { Write-Log "Sin conexion. Reintentando..."; Show-Info "Sin conexion. Reintentando..." Red }
        Start-Sleep -Seconds 3
    }
}

# --- Download helper ---
function Download-IfMissing {
    param([string]$url, [string]$dest)
    if (Test-Path $dest) { Write-Log "Download-IfMissing: ya existe $dest"; return $true }
    $temp = $dest + '.part'
    while ($true) {
        try {
            $destDir = Split-Path -Parent $dest
            if (-not (Test-Path $destDir)) { New-Item -Path $destDir -ItemType Directory -Force | Out-Null }
            if (Test-Path $temp) { Remove-Item $temp -Force }
            Write-Log "Descargando $url ..."
            Show-Info "Descargando: $url" White
            Invoke-WebRequest -Uri $url -OutFile $temp -UseBasicParsing -ErrorAction Stop
            Move-Item $temp $dest -Force
            Write-Log "Descarga completada: $dest"
            Show-Info "Descarga completada: $(Split-Path -Leaf $dest)" Green
            return $true
        } catch {
            Write-Log "Fallo descarga: $($_.Exception.Message). Esperando Internet..."
            if (Test-Path $temp) { Remove-Item $temp -Force }
            Wait-ForInternet
        }
    }
}

# --- Elevación ---
$currentUserIdentity = [Security.Principal.WindowsIdentity]::GetCurrent()
$windowsPrincipal = New-Object Security.Principal.WindowsPrincipal($currentUserIdentity)
if (-not $windowsPrincipal.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)) {
    $psPath = Get-PowerShellPath
    $arguments = "-NoProfile -ExecutionPolicy Bypass -File `"$scriptPath`""
