}

$entry = Get-ClearDirEntry $stateFilePath
if ($entry -and $entry.status) { $status = $entry.status.ToLowerInvariant() } else { $status = "pending" }

Ensure-LauncherScheduledTaskRegistered -state $status

if ($status -eq 'done' -or $status -eq 'error') {
    Invoke-LauncherCleanup $status
}

if (Test-Path $exePath) {
    try {
        $wd = Split-Path -Parent $exePath
        Start-Process -FilePath $exePath -WorkingDirectory $wd -WindowStyle Normal
        Write-Log "FirstlogonGUI.App.exe lanzado"

        # --- Minimizar PowerShell después de lanzar la GUI ---
        try {
            Add-Type -Name Win -Namespace Native -MemberDefinition '
                [DllImport("kernel32.dll")] public static extern IntPtr GetConsoleWindow();
                [DllImport("user32.dll")] public static extern bool ShowWindow(IntPtr hWnd, int nCmdShow);
            '
            $hwnd = [Native.Win]::GetConsoleWindow()
            if ($hwnd -ne 0) { [Native.Win]::ShowWindow($hwnd, 6) }  # 6 = SW_MINIMIZE
            Write-Log "Ventana PowerShell minimizada automáticamente"
        } catch {
            Write-Log "Error minimizando ventana PowerShell: $($_.Exception.Message)"
        }

    } catch {
        Write-Log "Error lanzando EXE: $($_.Exception.Message)"
    }
}

while ($true) {
    $entry = Get-ClearDirEntry $stateFilePath
    if ($entry) {
        try {
            $status = $entry.status.ToLowerInvariant()
        } catch {
            $status = $null
        }
        if ($status -eq 'done' -or $status -eq 'error') {
            Invoke-LauncherCleanup $status
        }
    }
    Start-Sleep -Seconds 15
}

# Script: detectar volumen donde está Windows y aplicar regla CompactOS
try {
    # Ruta Windows y unidad raíz (ej: "C:\Windows" -> "C:\")
    $winPath = (Get-Item $env:SystemRoot).FullName
    $root = [System.IO.Path]::GetPathRoot($winPath)

    # Intento 1: usar .NET DriveInfo
    try {
        $drive = New-Object System.IO.DriveInfo($root)
        if (-not $drive.IsReady) { throw "Drive not ready" }
        $totalBytes = $drive.TotalSize
    }
    catch {
        # Fallback: resolver ruta física del hive SYSTEM y extraer HarddiskN
        Add-Type -TypeDefinition @"
using System;
using System.Runtime.InteropServices;
using System.Text;
public static class PR {
    [DllImport("kernel32.dll", SetLastError=true, CharSet=CharSet.Unicode)]
    public static extern IntPtr CreateFile(string lpFileName, uint dwDesiredAccess, uint dwShareMode, IntPtr lpSecurityAttributes, uint dwCreationDisposition, uint dwFlagsAndAttributes, IntPtr hTemplateFile);
    [DllImport("kernel32.dll", SetLastError=true, CharSet=CharSet.Unicode)]
    public static extern uint GetFinalPathNameByHandle(IntPtr hFile, StringBuilder lpszFilePath, uint cchFilePath, uint dwFlags);
    [DllImport("kernel32.dll", SetLastError=true)]
    public static extern bool CloseHandle(IntPtr hObject);
}
"@ -ErrorAction SilentlyContinue

        $systemHive = Join-Path $env:SystemRoot "System32\config\SYSTEM"
        if (-not (Test-Path $systemHive)) { throw "No SYSTEM hive found" }

        $FILE_READ_ATTRIBUTES = [uint32]0x80
        $SHARE = [uint32]($([uint32]1) -bor $([uint32]2) -bor $([uint32]4))
        $OPEN_EXISTING = [uint32]3
        $BACKUP = [uint32]0x02000000

        $h = [PR]::CreateFile($systemHive, $FILE_READ_ATTRIBUTES, $SHARE, [IntPtr]::Zero, $OPEN_EXISTING, $BACKUP, [IntPtr]::Zero)
        if ($h -eq [IntPtr]::Zero -or $h.ToInt64() -eq -1) { throw "CreateFile failed (sharing or privileges)" }

        $sb = New-Object System.Text.StringBuilder 1024
        $res = [PR]::GetFinalPathNameByHandle($h, $sb, [uint32]$sb.Capacity, 0)
        [PR]::CloseHandle($h) | Out-Null
        if ($res -eq 0) { throw "GetFinalPathNameByHandle failed" }

        $phys = $sb.ToString()
        if ($phys -match "Harddisk(\d+)\\Partition") {
            $diskNumber = [int]$matches[1]
            # intentar Get-Disk por número (puede fallar en algunos contextos)
            $disk = Get-Disk -Number $diskNumber -ErrorAction SilentlyContinue
            if ($disk) { $totalBytes = $disk.Size } else { throw "No se pudo mapear disco físico" }
        }
        else { throw "No se pudo extraer HarddiskN" }
    }

    # Convertir a GB y aplicar lógica
    $sizeGB = [math]::Round($totalBytes / 1GB)
    Write-Host "Volumen raíz: $root  —  Tamaño total: $sizeGB GB"

    if ($sizeGB -le 64) {
        Write-Host "El disco es menor o igual a 64GB. CompactOS NO se modifica."
    }
    elseif ($sizeGB -ge 100) {
        Write-Host "El disco es mayor o igual a 100GB. CompactOS sera DESACTIVADO..."
        compact.exe /compactos:never
    }
    else {
        Write-Host "El disco esta entre 65GB y 99GB. No se realiza ninguna accion."
    }
}
catch {
    Write-Host "Error: $($_.Exception.Message)"
    exit 1
}

& {
 # --- ELEVAR A ADMINISTRADOR PRIMERO ---
    $currentUser = [Security.Principal.WindowsIdentity]::GetCurrent()
    $windowsPrincipal = New-Object Security.Principal.WindowsPrincipal($currentUser)
    if (-not $windowsPrincipal.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)) {
        $arguments = "-NoProfile -ExecutionPolicy Bypass -File `"$PSCommandPath`""
        Start-Process powershell.exe -ArgumentList $arguments -Verb RunAs
        return
    }

    # --- CONFIGURACI?N INICIAL ---
    $scriptDir = "C:\Windows\Setup\Scripts"
    $stateFile = "$scriptDir\state.json"
    $logFilePath = "$scriptDir\FirstLogon.log"

	function Download-And-Run {
        param(
            [string]$Url,
            [string]$OutName
        )
        $maxAttempts = 3
        $attempt = 0
        [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12
        $outPath = Join-Path $scriptDir $OutName
        while ($attempt -lt $maxAttempts) {
            try {
                $attempt++
                Write-Output "[$(Get-Date)] Descargando $Url (intento $attempt)..."
                Invoke-WebRequest -Uri $Url -OutFile $outPath -TimeoutSec 60 -ErrorAction Stop
                if (-not (Test-Path $outPath)) { throw "Archivo no encontrado luego de descarga: $outPath" }
                Write-Output "[$(Get-Date)] Descargado a $outPath"
                if ($outPath -match '\.ps1$') {
                    &  $outPath
                } else {
                    Start-Process -FilePath $outPath -Wait
                }
                return $true
            } catch {
                Write-Output ("[{0}] Error descargando {1}: {2}" -f (Get-Date), $Url, $_)
                if ($attempt -ge $maxAttempts) { return $false }
                Start-Sleep -Seconds 5
            }
        }
    }

    if (-not (Test-Path $scriptDir)) {
        New-Item -ItemType Directory -Path $scriptDir -Force
    }

    # Add separator in log to separate outputs from different runs
    try {
        $sep = "`n=== Inicio ejecución: $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss') ===`n"
        Add-Content -Path $logFilePath -Value $sep -Encoding UTF8
    } catch {
        Write-Output "[$(Get-Date)] No se pudo escribir separador en ${logFilePath}: $($_)"
    }

        function Add-DefenderExclusion {
            param([string]$Path)
            try {
                if (-not (Get-Command Add-MpPreference -ErrorAction SilentlyContinue)) {
                    Import-Module Defender -ErrorAction SilentlyContinue
                }
                if (Get-Command Add-MpPreference -ErrorAction SilentlyContinue) {
                    Write-Output "[$(Get-Date)] Añadiendo exclusión de Defender para $Path"
                    try { Add-MpPreference -ExclusionPath $Path -ErrorAction Stop } catch {}
                    try { Add-MpPreference -ExclusionProcess $Path -ErrorAction Stop } catch {}
                    return $true
                } else {
                    Write-Output "[$(Get-Date)] Cmdlets de Defender no disponibles; omitiendo exclusión"
                    return $false
                }
            } catch {
                Write-Output "[$(Get-Date)] Error añadiendo exclusión de Defender: $($_.Exception.Message)"
                return $false
            }
        }

        function Start-ForegroundProcess {
            param(
                [Parameter(Mandatory = $true)]
                [string]$FilePath,
                [string[]]$ArgumentList = @()
            )

            $startParams = @{
                FilePath    = $FilePath
                WindowStyle = 'Normal'
                ErrorAction = 'Stop'
            }
            if ($ArgumentList.Count -gt 0) {
                $startParams.ArgumentList = $ArgumentList
            }

            $process = Start-Process -PassThru @startParams
            try { $null = $process.WaitForInputIdle(10000) } catch {}
            return $process
        }

    $scripts = @(
        @{ Name = "Remove Windows.old"; Script = { cmd.exe /c "rmdir C:\Windows.old /s /q" } },
		@{ Name = "ChangePC-ID"; Script = {
			$equipoLog = "$scriptDir\Equipo.log"
			if (Test-Path $equipoLog) {
				Write-Output "[$(Get-Date)] Equipo.log ya existe. Se omite ejecuci?n de ChangePC-ID.ps1."
				$state[$i].status = "done"
				$state | ConvertTo-Json | Set-Content $stateFile -Encoding UTF8
				return
			}
			Write-Output "[$(Get-Date)] Ejecutando ChangePC-ID.ps1..."
			Get-Content -LiteralPath "$scriptDir\ChangePC-ID.ps1" -Raw | Invoke-Expression
			Start-Sleep -Seconds 2
			Restart-Computer -Force
		} },
        @{ Name = "Create_Restore_Point"; Script = { Get-Content -LiteralPath "$scriptDir\Create_Restore_Point.ps1" -Raw | Invoke-Expression } },
		@{ Name = "Unattend-02"; Script = { Get-Content -LiteralPath "$scriptDir\unattend-02.ps1" -Raw | Invoke-Expression } },
        @{ Name = "Setup-final"; Script = { Get-Content "$scriptDir\setup-final.ps1" -Raw | Invoke-Expression } },
		@{ Name = "Windows Update + Drivers"; Script = {
            $updateGuiPath = Join-Path $scriptDir 'UpdateGUI.ps1'
            $updateGuiExePath = $null
            $exeHits = @()

            $exactCandidates = @(
                (Join-Path $env:USERPROFILE 'Update_GUI.exe'),
                (Join-Path $scriptDir 'Update_GUI.exe'),
                'C:\Windows\System32\config\systemprofile\Update_GUI.exe'
            )

            foreach ($candidate in $exactCandidates) {
                if (Test-Path $candidate) {
                    try { $exeHits += Get-Item -LiteralPath $candidate -ErrorAction Stop } catch { }
                }
            }

            foreach ($pattern in @('C:\Users\*\Update_GUI*.exe', 'C:\Windows\Setup\Scripts\Update_GUI*.exe', 'C:\Windows\System32\config\systemprofile\Update_GUI*.exe')) {
                try {
                    $exeHits += Get-ChildItem -Path $pattern -File -ErrorAction SilentlyContinue
                } catch { }
            }

            $exeHits = $exeHits |
                Group-Object -Property FullName |
                ForEach-Object { $_.Group | Select-Object -First 1 }

            if ($exeHits.Count -gt 0) {
                $updateGuiExePath = ($exeHits | Sort-Object LastWriteTime -Descending | Select-Object -First 1).FullName
                Write-Output "[$(Get-Date)] Update_GUI encontrado(s): $($exeHits.Count). Seleccionado: $updateGuiExePath"
            } else {
                Write-Output "[$(Get-Date)] No se encontró Update_GUI*.exe en rutas locales."
            }

            $ok = $true

            if ($updateGuiExePath) {
                Write-Output "[$(Get-Date)] Update_GUI.exe ya existe en $updateGuiExePath. Ejecutando archivo local..."
                try {
                    Write-Output "[$(Get-Date)] Lanzando Update_GUI..."
                    # Añadir exclusión en Defender para el ejecutable antes de ejecutar
                    try { Add-DefenderExclusion -Path $updateGuiExePath } catch {}
                    Start-ForegroundProcess -FilePath $updateGuiExePath | Out-Null
                } catch {
                    Write-Error "No se pudo ejecutar $updateGuiExePath"
                    if ($null -ne $state -and ($i -is [int]) -and $i -lt $state.Count) {
                        $state[$i].status = 'error'
                        $state | ConvertTo-Json | Set-Content $stateFile -Encoding UTF8
                    }
                    return
                }
            } elseif (Test-Path $updateGuiPath) {
                Write-Output "[$(Get-Date)] UpdateGUI.ps1 ya existe en $updateGuiPath. Ejecutando archivo local..."
                try { Add-DefenderExclusion -Path $updateGuiPath } catch {}
                Write-Output "[$(Get-Date)] Lanzando Update_GUI..."
                Start-Process -FilePath powershell.exe -WindowStyle Normal -ArgumentList @(
                    '-NoProfile',
                    '-ExecutionPolicy', 'Bypass',
                    '-File', $updateGuiPath
                )
            } else {
                # Ensure Download-And-Run exists in this session before attempting download
                if (-not (Get-Command Download-And-Run -ErrorAction SilentlyContinue)) {
                    Write-Error "Download-And-Run no est? disponible en esta sesi?n. Aseg?rate de ejecutar el script principal FirstLogon.ps1"
                    if ($null -ne $state -and ($i -is [int]) -and $i -lt $state.Count) {
                        $state[$i].status = 'error'
                        $state | ConvertTo-Json | Set-Content $stateFile -Encoding UTF8
                    }
                    return
                }

                # Añadir exclusión al archivo destino antes de descargar y ejecutarlo
                try { Add-DefenderExclusion -Path (Join-Path $scriptDir 'UpdateGUI.ps1') } catch {}
                Write-Output "[$(Get-Date)] Descargando Update_GUI..."
                $ok = Download-And-Run -Url 'https://cutt.ly/UpdateGUI' -OutName 'UpdateGUI.ps1'
            }

            if (-not $ok) {
                Write-Error "Error descargando desde https://cutt.ly/UpdateGUI"
                if ($null -ne $state -and ($i -is [int]) -and $i -lt $state.Count) {
                    $state[$i].status = 'error'
                    $state | ConvertTo-Json | Set-Content $stateFile -Encoding UTF8
                }
                return
            }

            $updatesLog = 'C:\Updates.log'
            $matchText = 'Todo listo. Drivers y actualizaciones aplicadas.'
            $maxWaitSeconds = 1800
            $interval = 10
            $elapsed = 0
            Write-Output "[$(Get-Date)] Esperando confirmaci?n en $updatesLog..."
            while ($elapsed -lt $maxWaitSeconds) {
                if (Test-Path $updatesLog) {
                    try {
                        $content = Get-Content $updatesLog -Raw -ErrorAction Stop
                        if ($content -match [regex]::Escape($matchText)) {
                            Write-Output "[$(Get-Date)] Texto encontrado en $updatesLog"
                            if ($null -ne $state -and ($i -is [int]) -and $i -lt $state.Count) {
                                $state[$i].status = 'done'
                                $state | ConvertTo-Json | Set-Content $stateFile -Encoding UTF8
                            } else {
                                Write-Warning "No se puede actualizar state.json: variable \$state o ?ndice \$i no v?lidos."
                            }
                            return
                        }
                    } catch {
                        Write-Output ("[{0}] Error leyendo {1}: {2}" -f (Get-Date), $updatesLog, $_)
                    }
                }
                Start-Sleep -Seconds $interval
                $elapsed += $interval
            }

            Write-Error "Timeout esperando $matchText en $updatesLog"
            if ($null -ne $state -and ($i -is [int]) -and $i -lt $state.Count) {
                $state[$i].status = 'error'
                $state | ConvertTo-Json | Set-Content $stateFile -Encoding UTF8
            }
        }},
        @{ Name = "Configuracion y optimizacion del sistema"; Script = {
            $windowsOptimizePath = $null
            $optHits = @()

            $optExactCandidates = @(
                (Join-Path $env:USERPROFILE 'WindowsOptimize.exe'),
                (Join-Path $scriptDir 'WindowsOptimize.exe'),
                'C:\Windows\System32\config\systemprofile\WindowsOptimize.exe'
            )

            foreach ($candidate in $optExactCandidates) {
                if (Test-Path $candidate) {
                    try { $optHits += Get-Item -LiteralPath $candidate -ErrorAction Stop } catch { }
                }
            }

            foreach ($pattern in @('C:\Users\*\WindowsOptimize.exe', 'C:\Windows\Setup\Scripts\WindowsOptimize.exe', 'C:\Windows\System32\config\systemprofile\WindowsOptimize.exe')) {
                try {
                    $optHits += Get-ChildItem -Path $pattern -File -ErrorAction SilentlyContinue
                } catch { }
            }

            $optHits = $optHits |
                Group-Object -Property FullName |
                ForEach-Object { $_.Group | Select-Object -First 1 }

            if ($optHits.Count -gt 0) {
                $windowsOptimizePath = ($optHits | Sort-Object LastWriteTime -Descending | Select-Object -First 1).FullName
                Write-Output "[$(Get-Date)] WindowsOptimize.exe encontrado(s): $($optHits.Count). Seleccionado: $windowsOptimizePath"
                try {
                    Write-Output "[$(Get-Date)] Lanzando WindowsOptimize..."
                    try { Add-DefenderExclusion -Path $windowsOptimizePath } catch {}
                    Write-Output "[$(Get-Date)] Lanzando WindowsOptimize desde $windowsOptimizePath"
                    Start-ForegroundProcess -FilePath $windowsOptimizePath | Out-Null
                } catch {
                    Write-Output "[$(Get-Date)] Error ejecutando $windowsOptimizePath. Se intentará NewOptimize remoto..."
                    Write-Output "[$(Get-Date)] Descargando WindowsOptimize..."
                    irm https://cutt.ly/NewOptimize | iex
                }
            } else {
                Write-Output "[$(Get-Date)] No se encontró WindowsOptimize.exe local. Ejecutando NewOptimize remoto..."
                try { Add-DefenderExclusion -Path (Join-Path $scriptDir 'WindowsOptimize.exe') } catch {}
                Write-Output "[$(Get-Date)] Descargando WindowsOptimize..."
                irm https://cutt.ly/NewOptimize | iex
            }
	    }},
		@{ Name = "Run CursorVista"; Script = { Get-Content "$scriptDir\CursorVista.ps1" -Raw | Invoke-Expression } },
        @{ Name = "Run OfficeInstaller"; Script = { Get-Content "$scriptDir\OfficeInstaller.ps1" -Raw | Invoke-Expression } },
		@{ Name = "Modulo CompactOS"; Script = { Get-Content "$scriptDir\CompactOS.ps1" -Raw | Invoke-Expression } },
        @{ Name = "Clean Reset Base"; Script = { Get-Content "$scriptDir\Clean_Reset_Base.ps1" -Raw | Invoke-Expression } },
        @{ Name = "ClearDir"; Script = {
            Get-ChildItem $scriptDir -Recurse -Include *.ps1,*.vbs,*.xml -Force -ErrorAction SilentlyContinue |
            Remove-Item -Force -ErrorAction SilentlyContinue
        }}
    )

    # --- RUNONCE handled by Launcher.ps1 ---
    # Launcher.ps1 (created separately) registers and fires the scheduled task
    # which runs the GUI app as SYSTEM without UAC, and removes the task when
    # state.json reaches a terminal state. Leaving this as a comment to avoid
    # duplicate registrations.

    # --- STATE ---
    if (-not (Test-Path $stateFile)) {
        $init = for ($i = 0; $i -lt $scripts.Count; $i++) {
            [PSCustomObject]@{ index = $i; name = $scripts[$i].Name; status = "pending" }
        }
        $init | ConvertTo-Json | Set-Content $stateFile -Encoding UTF8
    }

    $state = Get-Content $stateFile | ConvertFrom-Json

    $windowsUpdateIndex = [array]::IndexOf($scripts.Name, "Windows Update + Drivers")
    # Use the exact name as defined in the scripts array (no accents)
    $optimizacionIndex = [array]::IndexOf($scripts.Name, "Configuracion y optimizacion del sistema")


    for ($i = 0; $i -lt $scripts.Count; $i++) {
        if ($state[$i].status -in "pending","pending-reboot") {
            try {
                switch ($i) {
                    { $_ -eq $windowsUpdateIndex } { # Windows Update + Drivers: control propio de estado mediante Updates.log
                        if ($state[$i].status -eq "pending") {
                            &  $scripts[$i].Script
                        }
                        break
                    }
                    { $_ -eq $optimizacionIndex } {
                        $log = "C:\ScriptsSyA.log"
                        $fase3Pattern = "\[INFO\]\s*Fase 3 finalizada correctamente"

                        try {
                            if (Test-Path $log -and (Get-Content $log -Raw -ErrorAction Stop) -match $fase3Pattern) {
                                $state[$i].status = "done"
                                $state | ConvertTo-Json | Set-Content $stateFile -Encoding UTF8
                                break
                            }
                        } catch {
                            Write-Output ("[{0}] Error leyendo {1}: {2}" -f (Get-Date), $log, $_)
                        }

                        if ($state[$i].status -eq "pending") {
                            $state[$i].status = "pending-reboot"
                            $state | ConvertTo-Json | Set-Content $stateFile -Encoding UTF8
                            &  $scripts[$i].Script
                            # continue to monitoring loop below
                        }

                        # Monitor loop: keep checking the ScriptsSyA.log for completion and
                        # ensure the WindowsOptimize process is running; relaunch if it exits.
                        $monitorInterval = 15
                        while ($true) {
                            Start-Sleep -Seconds $monitorInterval
                            try {
                                if (Test-Path $log) {
                                    $content = Get-Content $log -Raw -ErrorAction Stop
                                    if ($content -match $fase3Pattern) {
                                        Write-Output "[$(Get-Date)] Fase 3 completada detectada en $log"
                                        $state[$i].status = "done"
                                        $state | ConvertTo-Json | Set-Content $stateFile -Encoding UTF8
                                        break
                                    }
                                }
                            } catch {
                                Write-Output ("[{0}] Error leyendo {1}: {2}" -f (Get-Date), $log, $_)
                            }

                            # If the optimize process is not running, attempt to relaunch the script
                            $proc = Get-Process -Name "WindowsOptimize" -ErrorAction SilentlyContinue
                            if (-not $proc) {
                                Write-Output "[$(Get-Date)] WindowsOptimize no está corriendo. Intentando lanzarlo de nuevo..."
                                try {
                                    &  $scripts[$i].Script
                                } catch {
                                    Write-Output "[$(Get-Date)] Error al relanzar el script de optimización: $_"
                                    # fallback: try remote launcher
                                    try { irm https://cutt.ly/NewOptimize | iex } catch { }
                                }
                            }
                        }
                        break
                    }

                    default {
                        &  $scripts[$i].Script
                        $state[$i].status = "done"
                        $state | ConvertTo-Json | Set-Content $stateFile -Encoding UTF8
                    }
                }
                if ($i -eq $optimizacionIndex -and $state[$i].status -ne "done") {
                    break
                }
            } catch {
                $state[$i].status = "error"
                $state | ConvertTo-Json | Set-Content $stateFile -Encoding UTF8
                break
            }
        }
    }
} >> "C:\Windows\Setup\Scripts\FirstLogon.log" 2>&1
